#include <iostream>

using namespace std;

class Solution {
public: 
    int bitwiseAND(vector<int>& nums) {
        int result = 0;
        for(int i = 0; i < nums.size(); i++)
            result |= nums[i];
        return result;
    }
};

int main() {
    Solution solution;
    vector<int> nums = {1, 2};
    int res = solution.bitwiseAND(nums);
    cout << res << endl;
    return 0;
}

